1	import { describe, it } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { existsSync, readFileSync } from 'node:fs';
4	import { resolve, dirname } from 'node:path';
5	import { fileURLToPath } from 'node:url';
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	const ROOT = resolve(__dirname, '..');
9	
10	function readPkg(rel) {
11	  return JSON.parse(readFileSync(resolve(ROOT, rel), 'utf-8'));
12	}
13	
14	describe('Client dependencies', () => {
15	  it('react is a dependency',            () => assert.ok(readPkg('client/package.json').dependencies?.react));
16	  it('react-dom is a dependency',        () => assert.ok(readPkg('client/package.json').dependencies?.['react-dom']));
17	  it('vite is a devDependency',          () => assert.ok(readPkg('client/package.json').devDependencies?.vite));
18	  it('@vitejs/plugin-react is a devDep', () => assert.ok(readPkg('client/package.json').devDependencies?.['@vitejs/plugin-react']));
19	  it('vitest is a devDependency',        () => assert.ok(readPkg('client/package.json').devDependencies?.vitest));
20	  it('@testing-library/react is a devDep',    () => assert.ok(readPkg('client/package.json').devDependencies?.['@testing-library/react']));
21	  it('@testing-library/jest-dom is a devDep', () => assert.ok(readPkg('client/package.json').devDependencies?.['@testing-library/jest-dom']));
22	  it('jsdom is a devDependency',         () => assert.ok(readPkg('client/package.json').devDependencies?.jsdom));
23	  it('eslint is a devDependency',        () => assert.ok(readPkg('client/package.json').devDependencies?.eslint));
24	});
25	
26	describe('Client scripts', () => {
27	  it('has scripts.test', () => assert.ok(readPkg('client/package.json').scripts?.test));
28	  it('has scripts.lint', () => assert.ok(readPkg('client/package.json').scripts?.lint));
29	});
30	
31	describe('Client files', () => {
32	  const files = [
33	    'client/eslint.config.js',
34	    'client/vite.config.js',
35	    'client/index.html',
36	    'client/src/main.jsx',
37	    'client/src/App.jsx',
38	    'client/src/App.test.jsx',
39	  ];
40	  for (const f of files) {
41	    it(`exists: ${f}`, () => assert.ok(existsSync(resolve(ROOT, f)), `Missing: kanban/${f}`));
42	  }
43	});
44	
45	// NOTE: readFileSync is called inside each it() — never at describe() level —
46	// so a missing file fails this specific test cleanly instead of crashing the suite.
47	describe('vite.config.js proxy settings', () => {
48	  it('proxies /api to localhost:3001', () => {
49	    const cfg = readFileSync(resolve(ROOT, 'client/vite.config.js'), 'utf-8');
50	    assert.ok(cfg.includes("'/api'") || cfg.includes('"/api"'));
51	    assert.ok(cfg.includes('localhost:3001'));
52	  });
53	
54	  it('proxies /ws with ws: true', () => {
55	    const cfg = readFileSync(resolve(ROOT, 'client/vite.config.js'), 'utf-8');
56	    assert.ok(cfg.includes("'/ws'") || cfg.includes('"/ws"'));
57	    assert.ok(cfg.includes('ws: true'));
58	  });
59	
60	  it('uses @vitejs/plugin-react', () => {
61	    const cfg = readFileSync(resolve(ROOT, 'client/vite.config.js'), 'utf-8');
62	    assert.ok(cfg.includes('@vitejs/plugin-react'));
63	  });
64	
65	  it('configures vitest environment as jsdom', () => {
66	    const cfg = readFileSync(resolve(ROOT, 'client/vite.config.js'), 'utf-8');
67	    assert.ok(cfg.includes('jsdom'));
68	  });
69	});
